'    <div class="process-card rv d1"><div class="p-num">01</div><div class="p-icon">&#127919;</div><div class="p-title">\u05d9\u05e2\u05d3 \u05de\u05d3\u05d5\u05d9\u05e7 - \u05dc\u05d0 \u05e0\u05d9\u05d7\u05d5\u05e9</div><div class="p-desc">\u05d0\u05e0\u05d9 \u05de\u05ea\u05e8\u05d2\u05de\u05ea \u05d0\u05ea \u05d4\u05d9\u05e2\u05d3 \u05e9\u05dc\u05da \u05dc\u05de\u05e1\u05e4\u05e8\u05d9\u05dd, \u05d0\u05d9\u05de\u05d5\u05e0\u05d9\u05dd, \u05d0\u05e8\u05d5\u05d7\u05d5\u05ea \u05d5\u05de\u05d3\u05d3\u05d9\u05dd. \u05d4\u05db\u05dc \u05d1-100% \u05de\u05e2\u05e7\u05d1 \u05d5\u05de\u05d5\u05ea\u05d0\u05dd \u05d0\u05d9\u05e9\u05d9\u05ea \u05dc\u05e9\u05d2\u05e8\u05d4 \u05e9\u05dc\u05da. \u05d9\u05e9 \u05e9\u05d9\u05e0\u05d5\u05d9? \u05d0\u05e0\u05d9 \u05e2\u05dc \u05d6\u05d4 \u05de\u05d9\u05d3\u05d9\u05ea.</div></div>',
