'    <div class="feat-card rv d5"><div class="feat-check">&#10003;</div><div class="feat-title">\u05d2\u05d9\u05e9\u05d4 \u05dc\u05e7\u05d1\u05e6\u05d9 \u05e4\u05e8\u05d9\u05de\u05d9\u05d5\u05dd</div><div class="feat-desc">\u05de\u05d3\u05e8\u05d9\u05db\u05d9\u05dd \u05dc\u05d7\u05d2\u05d9\u05dd, \u05d0\u05e8\u05d5\u05e2\u05d9\u05dd \u05de\u05d9\u05d5\u05d7\u05d3\u05d9\u05dd \u05d5\u05e1\u05d9\u05d8\u05d5\u05d0\u05e6\u05d9\u05d5\u05ea \u05de\u05d5\u05e8\u05db\u05d1\u05d5\u05ea</div></div>',
