'  <h2 class="section-h2 rv">\u05e9\u05d0\u05dc\u05d5\u05ea \u05e9\u05d0\u05d5\u05dc\u05d9 <em>\u05e2\u05dc\u05d5 \u05dc\u05da</em></h2>',
'  <div class="faq-list">',
'    <div class="faq-item"><button class="faq-q">\u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05d7\u05d9\u05d9\u05d1\u05ea \u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05e0\u05d5\u05d9\u05d9\u05d4 \u05dc\u05d7\u05d3\u05e8 \u05db\u05d5\u05e9\u05e8?<span class="faq-icon">+</span></button><div class="faq-a"><div class="faq-a-inner">\u05dc\u05d0 \u05d7\u05d9\u05d9\u05d1\u05ea! \u05d0\u05e0\u05d9 \u05de\u05d5\u05ea\u05d0\u05de\u05ea \u05dc\u05d0\u05d9\u05de\u05d5\u05e0\u05d9\u05dd \u05d1\u05d7\u05d3\u05e8 \u05db\u05d5\u05e9\u05e8, \u05d1\u05d1\u05d9\u05ea, \u05e2\u05dd \u05e6\u05d9\u05d5\u05d3 \u05de\u05d9\u05e0\u05d9\u05de\u05dc\u05d9 \u05d0\u05d5 \u05dc\u05dc\u05d0 \u05e6\u05d9\u05d5\u05d3 \u05d1\u05db\u05dc\u05dc. \u05d4\u05db\u05dc \u05d9\u05d5\u05ea\u05d0\u05dd \u05d1\u05d3\u05d9\u05d5\u05e7 \u05dc\u05de\u05d4 \u05e9\u05d9\u05e9 \u05dc\u05da.</div></div></div>',
'    <div class="faq-item"><button class="faq-q">\u05ea\u05d5\u05da \u05db\u05de\u05d4 \u05d6\u05de\u05df \u05d0\u05e8\u05d0\u05d4 \u05ea\u05d5\u05e6\u05d0\u05d5\u05ea?<span class="faq-icon">+</span></button><div class="faq-a"><div class="faq-a-inner">\u05e8\u05d5\u05d1 \u05d4\u05dc\u05e7\u05d5\u05d7\u05d5\u05ea \u05de\u05ea\u05d7\u05d9\u05dc\u05d5\u05ea \u05dc\u05e8\u05d0\u05d5\u05ea \u05e9\u05d9\u05e0\u05d5\u05d9 \u05e8\u05d0\u05e9\u05d5\u05e0\u05d9 \u05ea\u05d5\u05da 3-4 \u05e9\u05d1\u05d5\u05e2\u05d5\u05ea. \u05ea\u05d5\u05e6\u05d0\u05d5\u05ea \u05de\u05e9\u05de\u05e2\u05d5\u05ea\u05d9\u05d5\u05ea \u05e0\u05e8\u05d0\u05d5\u05ea \u05d1\u05d3\u05e8\u05da \u05db\u05dc\u05dc \u05ea\u05d5\u05da 8-12 \u05e9\u05d1\u05d5\u05e2\u05d5\u05ea, \u05ea\u05dc\u05d5\u05d9 \u05d1\u05e0\u05e7\u05d5\u05d3\u05ea \u05d4\u05d4\u05ea\u05d7\u05dc\u05d4 \u05d5\u05d1\u05de\u05d7\u05d5\u05d9\u05d9\u05d1\u05d5\u05ea \u05dc\u05ea\u05d4\u05dc\u05d9\u05da.</div></div></div>',
'    <div class="faq-item"><button class="faq-q">\u05d0\u05e0\u05d9 \u05dc\u05d0 \u05e8\u05d5\u05e6\u05d4 \u05dc\u05d4\u05d9\u05e8\u05d0\u05d5\u05ea \u05d2\u05d1\u05e8\u05d9\u05ea<span class="faq-icon">+</span></button><div class="faq-a"><div class="faq-a-inner">\u05d0\u05d9\u05de\u05d5\u05df \u05db\u05d5\u05d7 \u05e0\u05db\u05d5\u05df \u05dc\u05e0\u05e9\u05d9\u05dd \u05d1\u05d5\u05e0\u05d4 \u05e2\u05e7\u05d5\u05de\u05d5\u05ea \u05d5\u05e4\u05e8\u05d5\u05e4\u05d5\u05e8\u05e6\u05d9\u05d5\u05ea - \u05dc\u05d0 \u05de\u05e1\u05ea \u05e9\u05e8\u05d9\u05e8 \u05d2\u05d1\u05e8\u05d9\u05ea. \u05d4\u05de\u05d8\u05e8\u05d4 \u05e9\u05dc\u05e0\u05d5 \u05d4\u05d9\u05d0 \u05d2\u05d5\u05e3 \u05e0\u05e9\u05d9, \u05d3\u05d5\u05de\u05d9\u05e0\u05e0\u05d8\u05d9 \u05d5\u05d0\u05e1\u05ea\u05d8\u05d9.</div></div></div>',
