'    const t=+e.target.dataset.count;let s=0,step=t/60;',
'    const tick=()=>{s=Math.min(s+step,t);e.target.textContent=Math.round(s)+(t===100?"%":"+");if(s<t)requestAnimationFrame(tick);};tick();}',
'}),{threshold:0.5});',
'document.querySelectorAll("[data-count]").forEach(el=>cObs.observe(el));',
'(function(){',
'  const track=document.getElementById("spl-track");if(!track)return;',
