'  function gp(){return Math.ceil(total/pp);}',
'  function bd(){dw.innerHTML="";for(let i=0;i<gp();i++){const li=document.createElement("li");li.className="spl-dot"+(i===0?" active":"");li.addEventListener("click",()=>go(i));dw.appendChild(li);}}',
'  function go(page){const pages=gp();cur=((page%pages)+pages)%pages;track.style.transform="translateX(-"+(cur*pp/total*100)+"%)";dw.querySelectorAll(".spl-dot").forEach((d,i)=>d.classList.toggle("active",i===cur));bar.style.width=(((cur+1)/pages)*100)+"%";}',
'  bd();',
