'  track.addEventListener("touchend",e=>{const dx=e.changedTouches[0].clientX-sx;if(Math.abs(dx)>40)go(dx<0?cur+1:cur-1);});',
'  window.addEventListener("resize",()=>{const np=gpp();if(np!==pp){pp=np;cur=0;bd();go(0);}});',
